+    #[test]
+    fn pressure_monitor_sample_count_saturates_at_numeric_limit() {
+        let pressure = Arc::new(SystemPressure::new());
+        let monitor = PressureMonitor::new(pressure, 1);
+        monitor.sample_count.store(u64::MAX - 1, Ordering::Relaxed);
+
+        monitor.sample();
